final class EncryptionManager {
    
    static let shared = EncryptionManager()
    private init() {}
    
    private let keychainKeyIdentifier = "com.tradingapp.encryption.key"
    
    func getOrCreateSymmetricKey() throws -> SymmetricKey {
        if let existingKeyData = try? SecureKeychainManager.shared.retrieve(key: keychainKeyIdentifier) {
            return SymmetricKey(data: existingKeyData)
        }
        
        let key = SymmetricKey(size: .bits256)
        let keyData = key.withUnsafeBytes { Data($0) }
        try SecureKeychainManager.shared.store(key: keychainKeyIdentifier, data: keyData, requireBiometric: false)
        return key
    }
    
    func encrypt(_ data: Data) throws -> Data {
        let key = try getOrCreateSymmetricKey()
        let sealedBox = try AES.GCM.seal(data, using: key)
        guard let combined = sealedBox.combined else {
            throw EncryptionError.encryptionFailed
        }
        return combined
    }
    
    func decrypt(_ data: Data) throws -> Data {
        let key = try getOrCreateSymmetricKey()
        let sealedBox = try AES.GCM.SealedBox(combined: data)
        return try AES.GCM.open(sealedBox, using: key)
    }
    
    func generateHMAC(for data: Data, key: SymmetricKey) -> Data {
        let hmac = HMAC<SHA256>.authenticationCode(for: data, using: key)
        return Data(hmac)
    }
    
    enum EncryptionError: Error {
        case encryptionFailed
        case decryptionFailed
        case keyGenerationFailed
    }
}

// MARK: - Biometric Authentication

final class BiometricAuthManager {
    
    static let shared = BiometricAuthManager()
    private init() {}
    
    enum BiometricError: Error {
        case notAvailable
        case authenticationFailed
        case userCancelled
        case lockout
    }
    
    func authenticateUser(reason: String, completion: @escaping (Result<Bool, BiometricError>) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Cancel"
        context.localizedFallbackTitle = "Use Passcode"
        
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            completion(.failure(.notAvailable))
            return
        }
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, error in
            DispatchQueue.main.async {
                if success {
                    completion(.success(true))
                } else if let laError = error as? LAError {
                    switch laError.code {
                    case .userCancel:
                        completion(.failure(.userCancelled))
                    case .biometryLockout:
                        completion(.failure(.lockout))
                    default:
                        completion(.failure(.authenticationFailed))
                    }
                } else {
                    completion(.failure(.authenticationFailed))
                }
            }
        }
    }
}

// MARK: - Models

struct Stock: Codable, Identifiable {
    let id: String
    let symbol: String
    let name: String
    var currentPrice: Decimal
    var previousClose: Decimal
    var dayHigh: Decimal
    var dayLow: Decimal
    var volume: Int64
    var lastUpdated: Date
    
    var changeAmount: Decimal {
        return currentPrice - previousClose
    }
    
    var changePercent: Decimal {
        guard previousClose != 0 else { return 0 }
        return (changeAmount / previousClose) * 100
    }
    
    var isPositive: Bool {
        return changeAmount >= 0
    }
}

enum OrderType: String, Codable, CaseIterable {
    case market = "MARKET"
    case limit = "LIMIT"
    case stopLoss = "STOP_LOSS"
    case stopLimit = "STOP_LIMIT"
    case trailingStop = "TRAILING_STOP"
}

enum OrderSide: String, Codable {
    case buy = "BUY"
    case sell = "SELL"
}

enum OrderStatus: String, Codable {
    case pending = "PENDING"
    case submitted = "SUBMITTED"
    case partiallyFilled = "PARTIALLY_FILLED"
    case filled = "FILLED"
    case cancelled = "CANCELLED"
    case rejected = "REJECTED"
    case expired = "EXPIRED"
}

enum TimeInForce: String, Codable, CaseIterable {
    case day = "DAY"
    case gtc = "GTC"
    case ioc = "IOC"
    case fok = "FOK"
}

struct TradeOrder: Codable, Identifiable {
    let id: String
    let symbol: String
    let side: OrderSide
    let type: OrderType
    let quantity: Decimal
    var limitPrice: Decimal?
    var stopPrice: Decimal?
    var trailingAmount: Decimal?
    let timeInForce: TimeInForce
    var status: OrderStatus
    var filledQuantity: Decimal
    var averageFilledPrice: Decimal?
    let createdAt: Date
    var updatedAt: Date
    var executedAt: Date?
    let clientOrderId: String
    
    var isActive: Bool {
        return [.pending, .submitted, .partiallyFilled].contains(status)
    }
    
    var totalValue: Decimal? {
        guard let price = averageFilledPrice else { return nil }
        return filledQuantity * price
    }
}

struct Position: Codable, Identifiable {
    let id: String
    let symbol: String
    let quantity: Decimal
    let averageCost: Decimal
    var currentPrice: Decimal
    var lastUpdated: Date
    
    var marketValue: Decimal {
        return quantity * currentPrice
    }
    
    var totalCost: Decimal {
        return quantity * averageCost
    }
    
    var unrealizedPnL: Decimal {
        return marketValue - totalCost
    }
    
    var unrealizedPnLPercent: Decimal {
        guard totalCost != 0 else { return 0 }
        return (unrealizedPnL / totalCost) * 100
    }
    
    var isProfit: Bool {
        return unrealizedPnL >= 0
    }
}

struct Portfolio: Codable {
    var cashBalance: Decimal
    var positions: [Position]
    var totalEquity: Decimal {
        return cashBalance + positions.reduce(0) { $0 + $1.marketValue }
    }
    var totalUnrealizedPnL: Decimal {
        return positions.reduce(0) { $0 + $1.unrealizedPnL }
    }
    var dayPnL: Decimal
    var dayPnLPercent: Decimal
    var buyingPower: Decimal
    var lastUpdated: Date
}

struct WatchlistItem: Codable, Identifiable {
    let id: String
    let symbol: String
    let name: String
    var currentPrice: Decimal
    var changePercent: Decimal
    var isPositive: Bool
}

// MARK: - Secure API Client

final class SecureAPIClient {
    
    static let shared = SecureAPIClient()
    
    private let session: URLSession
    private let baseURL: URL
    private let requestTimeout: TimeInterval = 30
    private var authToken: String?
    private let tokenLock = NSLock()
    
    private init() {
        let config = URLSessionConfiguration.ephemeral
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json",
            "X-Platform": "iOS",
            "X-App-Version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "1.0"
        ]
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        config.requestCachePolicy = .reloadIgnoringLocalCacheData
        config.urlCache = nil
        
        let delegate = SSLPinningDelegate()
        self.session = URLSession(configuration: config, delegate: delegate, delegateQueue: nil)
        self.baseURL = URL(string: "https://api.tradingplatform.com/v1")!
    }
    
    enum APIError: Error, LocalizedError {
        case invalidURL
        case encodingError
        case decodingError
        case networkError(Error)
        case serverError(Int, String?)
        case unauthorized
        case rateLimited
        case integrityCheckFailed
        case requestSigningFailed
        
        var errorDescription: String? {
            switch self {
            case .invalidURL: return "Invalid URL"
            case .encodingError: return "Failed to encode request"
            case .decodingError: return "Failed to decode response"
            case .networkError(let error): return "Network error: \(error.localizedDescription)"
            case .serverError(let code, let message): return "Server error \(code): \(message ?? "Unknown")"
            case .unauthorized: return "Authentication required"
            case .rateLimited: return "Too many requests. Please try again later."
            case .integrityCheckFailed: return "Device integrity check failed"
            case .requestSigningFailed: return "Request signing failed"
            }
        }
    }
    
    func setAuthToken(_ token: String) {
        tokenLock.lock()
        defer { tokenLock.unlock() }
        self.authToken = token
        
        // Store encrypted token in keychain
        if let tokenData = token.data(using: .utf8) {
            if let encrypted = try? EncryptionManager.shared.encrypt(tokenData) {
                try? SecureKeychainManager.shared.store(key: "auth_token", data: encrypted)
            }
        }
    }
    
    func clearAuthToken() {
        tokenLock.lock()
        defer { tokenLock.unlock() }
        self.authToken = nil
        try? SecureKeychainManager.shared.delete(key: "auth_token")
    }
    
    private func signRequest(_ request: inout URLRequest, body: Data?) throws {
        let timestamp = String(Int(Date().timeIntervalSince1970))
        let nonce = UUID().uuidString
        
        request.setValue(timestamp, forHTTPHeaderField: "X-Timestamp")
        request.setValue(nonce, forHTTPHeaderField: "X-Nonce")
        
        // Create signature payload
        var signaturePayload = "\(request.httpMethod ?? "GET")\(request.url?.path ?? "")\(timestamp)\(nonce)"
        if let body = body {
            signaturePayload += body.base64EncodedString()
        }
        
        guard let payloadData = signaturePayload.data(using: .utf8) else {
            throw APIError.requestSigningFailed
        }
        
        let key = try EncryptionManager.shared.getOrCreateSymmetricKey()
        let hmac = EncryptionManager.shared.generateHMAC(for: payloadData, key: key)
        request.setValue(hmac.base64EncodedString(), forHTTPHeaderField: "X-Signature")
    }
    
    func request<T: Decodable>(
        endpoint: String,
        method: String = "GET",
        body: Encodable? = nil,
        requiresAuth: Bool = true
    ) async throws -> T {
        // Integrity check for sensitive operations
        if requiresAuth {
            let integrity = DeviceIntegrityChecker.shared.performFullIntegrityCheck()
            if integrity.isJailbroken || integrity.isDebugged {
                throw APIError.integrityCheckFailed
            }
        }
        
        guard let url = URL(string: endpoint, relativeTo: baseURL) else {
            throw APIError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.timeoutInterval = requestTimeout
        
        if requiresAuth {
            tokenLock.lock()
            let token = authToken
            tokenLock.unlock()
            
            guard let token = token else {
                throw APIError.unauthorized
            }
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        var bodyData: Data?
        if let body = body {
            let encoder = JSONEncoder()
            encoder.dateEncodingStrategy = .iso8601
            bodyData = try encoder.encode(AnyEncodable(body))
            request.httpBody = bodyData
        }
        
        // Sign the request
        try signRequest(&request, body: bodyData)
        
        // Add device fingerprint
        request.setValue(generateDeviceFingerprint(), forHTTPHeaderField: "X-Device-Fingerprint")
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw APIError.networkError(NSError(domain: "Invalid response", code: -1))
        }
        
        switch httpResponse.statusCode {
        case 200...299:
            let decoder = JSONDecoder()
            decoder.dateDecodingStrategy = .iso8601
            do {
                return try decoder.decode(T.self, from: data)
            } catch {
                throw APIError.decodingError
            }
        case 401:
            clearAuthToken()
            throw APIError.unauthorized
        case 429:
            throw APIError.rateLimited
        default:
            let message = String(data: data, encoding: .utf8)
            throw APIError.serverError(httpResponse.statusCode, message)
        }
    }
    
    private func generateDeviceFingerprint() -> String {
        let deviceId = UIDevice.current.identifierForVendor?.uuidString ?? "unknown"
        let model = UIDevice.current.model
        let systemVersion = UIDevice.current.systemVersion
        let fingerprint = "\(deviceId)-\(model)-\(systemVersion)"
        
        if let data = fingerprint.data(using: .utf8) {
            let hash = SHA256.hash(data: data)
            return hash.compactMap { String(format: "%02x", $0) }.joined()
        }
        return deviceId
    }
}

// MARK: - SSL Pinning Delegate

final class SSLPinningDelegate: NSObject, URLSessionDelegate {
    
    // SHA256 hashes of the expected certificate public keys
    private let pinnedPublicKeyHashes: Set<String> = [
        "BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=",
        "CCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCC="
    ]
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Evaluate server trust
        var error: CFError?
        let isValid = SecTrustEvaluateWithError(serverTrust, &error)
        
        guard isValid else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Pin public key
        guard let serverCertificate = SecTrustGetCertificateAtIndex(serverTrust, 0) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        guard let serverPublicKey = SecCertificateCopyKey(serverCertificate),
              let serverPublicKeyData = SecKeyCopyExternalRepresentation(serverPublicKey, nil) as Data? else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let keyHash = SHA256.hash(data: serverPublicKeyData)
        let keyHashBase64 = Data(keyHash).base64EncodedString()
        
        if pinnedPublicKeyHashes.contains(keyHashBase64) {
            completionHandler(.useCredential, URLCredential(trust: serverTrust))
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
}

// MARK: - Helper for encoding

struct AnyEncodable: Encodable {
    private let _encode: (Encoder) throws -> Void
    
    init<T: Encodable>(_ wrapped: T) {
        _encode = wrapped.encode
    }
    
    func encode(to encoder: Encoder) throws {
        try _encode(encoder)
    }
}

