    func fetchPositions() async {
        do {
            let positions: [Position] = try await api.request(endpoint: "/positions")
            await MainActor.run {
                self.positions = positions
            }
        } catch {
            await MainActor.run {
                self.error = error.localizedDescription
            }
        }
    }
    
    // MARK: - Order Execution
    
    struct OrderRequest: Codable {
        let symbol: String
        let side: OrderSide
        let type: OrderType
        let quantity: Decimal
        let limitPrice: Decimal?
        let stopPrice: Decimal?
        let trailingAmount: Decimal?
        let timeInForce: TimeInForce
        let clientOrderId: String
    }
    
    struct OrderResponse: Codable {
        let order: TradeOrder
        let message: String
    }
    
    enum OrderValidationError: Error, LocalizedError {
        case insufficientFunds(required: Decimal, available: Decimal)
        case insufficientShares(required: Decimal, available: Decimal)
        case invalidQuantity
        case invalidPrice
        case marketClosed
        case symbolNotFound
        case orderLimitExceeded
        case riskLimitExceeded(String)
        
        var errorDescription: String? {
            switch self {
            case .insufficientFunds(let required, let available):
                return "Insufficient funds. Required: $\(required), Available: $\(available)"
            case .insufficientShares(let required, let available):
                return "Insufficient shares. Required: \(required), Available: \(available)"
            case .invalidQuantity:
                return "Invalid quantity. Must be greater than 0."
            case .invalidPrice:
                return "Invalid price specified."
            case .marketClosed:
                return "Market is currently closed."
            case .symbolNotFound:
                return "Symbol not found."
            case .orderLimitExceeded:
                return "Maximum number of open orders exceeded."
            case .riskLimitExceeded(let reason):
                return "Risk limit exceeded: \(reason)"
            }
        }
    }
    
    func validateOrder(
        symbol: String,
        side: OrderSide,
        type: OrderType,
        quantity: Decimal,
        limitPrice: Decimal?,
        stopPrice: Decimal?,
        currentPrice: Decimal
    ) throws {
        // Validate quantity
        guard quantity > 0 else {
            throw OrderValidationError.invalidQuantity
        }
        
        // Validate price for limit orders
        if type == .limit || type == .stopLimit {
            guard let price = limitPrice, price > 0 else {
                throw OrderValidationError.invalidPrice
            }
        }
        
        // Validate stop price
        if type == .stopLoss || type == .stopLimit {
            guard let stop = stopPrice, stop > 0 else {
                throw OrderValidationError.invalidPrice
            }
        }
        
        // Check buying power for buy orders
        if side == .buy {
            let estimatedCost: Decimal
            switch type {
            case .market:
                estimatedCost = quantity * currentPrice * Decimal(1.02) // 2% buffer
            case .limit:
                estimatedCost = quantity * (limitPrice ?? currentPrice)
            default:
                estimatedCost = quantity * currentPrice * Decimal(1.05)
            }
            
            if let portfolio = portfolio, estimatedCost > portfolio.buyingPower {
                throw OrderValidationError.insufficientFunds(
                    required: estimatedCost,
                    available: portfolio.buyingPower
                )
            }
        }
        
        // Check position for sell orders
        if side == .sell {
            if let position = positions.first(where: { $0.symbol == symbol }) {
                if quantity > position.quantity {
                    throw OrderValidationError.insufficientShares(
                        required: quantity,
                        available: position.quantity
                    )
                }
            } else {
                throw OrderValidationError.insufficientShares(required: quantity, available: 0)
            }
        }
        
        // Check open order limit
        if openOrders.count >= 50 {
            throw OrderValidationError.orderLimitExceeded
        }
        
        // Risk checks
        let orderValue = quantity * currentPrice
        if let portfolio = portfolio {
            let concentrationLimit = portfolio.totalEquity * Decimal(0.25) // 25% max concentration
            let existingExposure = positions
                .filter { $0.symbol == symbol }
                .reduce(Decimal(0)) { $0 + $1.marketValue }
            
            if side == .buy && (existingExposure + orderValue) > concentrationLimit {
                throw OrderValidationError.riskLimitExceeded(
                    "Position would exceed 25% portfolio concentration limit"
                )
            }
        }
    }
    
    func submitOrder(
        symbol: String,
        side: OrderSide,
        type: OrderType,
        quantity: Decimal,
        limitPrice: Decimal? = nil,
        stopPrice: Decimal? = nil,
        trailingAmount: Decimal? = nil,
        timeInForce: TimeInForce = .day
    ) async throws -> TradeOrder {
        // Perform integrity check before trade execution
        let integrity = DeviceIntegrityChecker.shared.performFullIntegrityCheck()
        guard !integrity.isJailbroken && !integrity.isDebugged else {
            throw SecureAPIClient.APIError.integrityCheckFailed
        }
        
        let clientOrderId = "ios-\(UUID().uuidString)"
        
        let orderRequest = OrderRequest(
            symbol: symbol,
            side: side,
            type: type,
            quantity: quantity,
            limitPrice: limitPrice,
            stopPrice: stopPrice,
            trailingAmount: trailingAmount,
            timeInForce: timeInForce,
            clientOrderId: clientOrderId
        )
        
        let response: OrderResponse = try await api.request(
            endpoint: "/orders",
            method: "POST",
            body: orderRequest
        )
        
        // Log trade for audit
        AuditLogger.shared.logTrade(order: response.order)
        
        await MainActor.run {
            self.openOrders.insert(response.order, at: 0)
        }
        
        // Refresh portfolio after order
        await fetchPortfolio()
        
        return response.order
    }
    
    func cancelOrder(orderId: String) async throws {
        struct CancelResponse: Codable {
            let success: Bool
            let message: String
        }
        
        let _: CancelResponse = try await api.request(
            endpoint: "/orders/\(orderId)/cancel",
            method: "POST"
        )
        
        await MainActor.run {
            if let index = self.openOrders.firstIndex(where: { $0.id == orderId }) {
                self.openOrders[index].status = .cancelled
                self.openOrders[index].updatedAt = Date()
            }
        }
        
        AuditLogger.shared.log(event: .orderCancelled, details: ["orderId": orderId])
    }
    
    func cancelAllOrders() async throws {
        struct BulkCancelResponse: Codable {
            let cancelledCount: Int
            let message: String
        }
        
        let _: BulkCancelResponse = try await api.request(
            endpoint: "/orders/cancel-all",
            method: "POST"
        )
        
        await MainActor.run {
            self.openOrders.removeAll()
        }
    }
    
    func fetchOpenOrders() async {
        do {
            let orders: [TradeOrder] = try await api.request(endpoint: "/orders?status=open")
            await MainActor.run {
                self.openOrders = orders
            }
        } catch {
            await MainActor.run {
                self.error = error.localizedDescription
            }
        }
    }
    
    func fetchOrderHistory(limit: Int = 50) async {
        do {
            let orders: [TradeOrder] = try await api.request(endpoint: "/orders/history?limit=\(limit)")
            await MainActor.run {
                self.orderHistory = orders
            }
        } catch {
            await MainActor.run {
                self.error = error.localizedDescription
            }
        }
    }
    
    // MARK: - Stock Data
    
    func fetchStockQuote(symbol: String) async throws -> Stock {
        return try await api.request(endpoint: "/quotes/\(symbol)")
    }
    
    func fetchWatchlist() async {
        do {
            let items: [WatchlistItem] = try await api.request(endpoint: "/watchlist")
            await MainActor.run {
                self.watchlist = items
            }
        } catch {
            await MainActor.run {
                self.error = error.localizedDescription
            }
        }
    }
    
    // MARK: - Real-time Updates
    
    func startPriceUpdates() {
        priceUpdateTimer = Timer.scheduledTimer(withTimeInterval: 5.0, repeats: true) { [weak self] _ in
            Task { [weak self] in
                await self?.refreshPrices()
            }
        }
    }
    
    func stopPriceUpdates() {
        priceUpdateTimer?.invalidate()
        priceUpdateTimer = nil
    }
    
    private func refreshPrices() async {
        await fetchPortfolio()
        await fetchWatchlist()
        await fetchOpenOrders()
    }
}

// MARK: - WebSocket Manager for Real-time Data

final class WebSocketManager: NSObject, URLSessionWebSocketDelegate {
    
    static let shared = WebSocketManager()
    
    private var webSocket: URLSessionWebSocketTask?
    private var session: URLSession?
    private var isConnected = false
    private var reconnectAttempts = 0
    private let maxReconnectAttempts = 5
    private var pingTimer: Timer?
    
    var onPriceUpdate: ((String, Decimal) -> Void)?
    var onOrderUpdate: ((TradeOrder) -> Void)?
    var onConnectionStatusChange: ((Bool) -> Void)?
    
    private override init() {
        super.init()
    }
    
    func connect(authToken: String) {
        let config = URLSessionConfiguration.default
        session = URLSession(configuration: config, delegate: self, delegateQueue: OperationQueue())
        
        guard let url = URL(string: "wss://ws.tradingplatform.com/v1/stream") else { return }
        
        var request = URLRequest(url: url)
        request.setValue("Bearer \(authToken)", forHTTPHeaderField: "Authorization")
        request.setValue(generateConnectionId(), forHTTPHeaderField: "X-Connection-Id")
        
        webSocket = session?.webSocketTask(with: request)
        webSocket?.resume()
        
        receiveMessage()
        startPingTimer()
    }
    
    func disconnect() {
        pingTimer?.invalidate()
        pingTimer = nil
        webSocket?.cancel(with: .goingAway, reason: nil)
        webSocket = nil
        isConnected = false
        onConnectionStatusChange?(false)
    }
    
    func subscribe(symbols: [String]) {
        let message: [String: Any] = [
            "action": "subscribe",
            "symbols": symbols,
            "channels": ["quotes", "orders"]
        ]
        
        if let data = try? JSONSerialization.data(withJSONObject: message),
           let string = String(data: data, encoding: .utf8) {
            webSocket?.send(.string(string)) { error in
                if let error = error {
                    print("WebSocket send error: \(error)")
                }
            }
        }
    }
    
    func unsubscribe(symbols: [String]) {
        let message: [String: Any] = [
            "action": "unsubscribe",
            "symbols": symbols
        ]
        
        if let data = try? JSONSerialization.data(withJSONObject: message),
           let string = String(data: data, encoding: .utf8) {
            webSocket?.send(.string(string)) { _ in }
        }
    }
    
    private func receiveMessage() {
        webSocket?.receive { [weak self] result in
            switch result {
            case .success(let message):
                switch message {
                case .string(let text):
                    self?.handleMessage(text)
                case .data(let data):
                    if let text = String(data: data, encoding: .utf8) {
                        self?.handleMessage(text)
                    }
                @unknown default:
                    break
                }
                self?.receiveMessage()
                
            case .failure(let error):
                print("WebSocket receive error: \(error)")
                self?.handleDisconnection()
            }
        }
    }
    
    private func handleMessage(_ text: String) {
        guard let data = text.data(using: .utf8),
              let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
              let type = json["type"] as? String else { return }
        
        switch type {
        case "quote":
            if let symbol = json["symbol"] as? String,
               let priceString = json["price"] as? String,
               let price = Decimal(string: priceString) {
                DispatchQueue.main.async {
                    self.onPriceUpdate?(symbol, price)
                }
            }
            
        case "order_update":
            if let orderData = try? JSONSerialization.data(withJSONObject: json["order"] as Any),
               let order = try? JSONDecoder().decode(TradeOrder.self, from: orderData) {
                DispatchQueue.main.async {
                    self.onOrderUpdate?(order)
                }
            }
            
        case "heartbeat":
            break
            
        default:
            break
        }
    }
    
    private func handleDisconnection() {
        isConnected = false
        DispatchQueue.main.async {
            self.onConnectionStatusChange?(false)
        }
        
        guard reconnectAttempts < maxReconnectAttempts else {
            print("Max reconnection attempts reached")
            return
        }
        
        reconnectAttempts += 1
        let delay = Double(min(pow(2.0, Double(reconnectAttempts)), 30.0))
        
        DispatchQueue.global().asyncAfter(deadline: .now() + delay) { [weak self] in
            // Attempt reconnection
            if let token = try? SecureKeychainManager.shared.retrieve(key: "auth_token"),
               let decrypted = try? EncryptionManager.shared.decrypt(token),
               let tokenString = String(data: decrypted, encoding: .utf8) {
                self?.connect(authToken: tokenString)
            }
        }
    }
    
    private func startPingTimer() {
        pingTimer = Timer.scheduledTimer(withTimeInterval: 30, repeats: true) { [weak self] _ in
            self?.webSocket?.sendPing { error in
                if let error = error {
                    print("Ping failed: \(error)")
                    self?.handleDisconnection()
                }
            }
        }
    }
    
    private func generateConnectionId() -> String {
        return UUID().uuidString
    }
    
    // URLSessionWebSocketDelegate
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask, didOpenWithProtocol protocol: String?) {
        isConnected = true
        reconnectAttempts = 0
        DispatchQueue.main.async {
            self.onConnectionStatusChange?(true)
        }
    }
    
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask, didCloseWith closeCode: URLSessionWebSocketTask.CloseCode, reason: Data?) {
        handleDisconnection()
    }
}

// MARK: - Audit Logger

final class AuditLogger {
    
    static let shared = AuditLogger()
    private init() {}
    
    enum AuditEvent: String {
        case login = "LOGIN"
        case logout = "LOGOUT"
        case tradeSubmitted = "TRADE_SUBMITTED"
        case tradeFilled = "TRADE_FILLED"
        case orderCancelled = "ORDER_CANCELLED"
        case integrityCheckFailed = "INTEGRITY_CHECK_FAILED"
        case biometricAuth = "BIOMETRIC_AUTH"
        case sessionExpired = "SESSION_EXPIRED"
        case suspiciousActivity = "SUSPICIOUS_ACTIVITY"
    }
    
    struct AuditEntry: Codable {
        let timestamp: Date
        let event: String
        let details: [String: String]
        let deviceId: String
        let sessionId: String
    }
    
    private var sessionId = UUID().uuidString
    private let logQueue = DispatchQueue(label: "com.tradingapp.audit", qos: .utility)
    private var pendingLogs: [AuditEntry] = []
    private let maxPendingLogs = 100
    
    func log(event: AuditEvent, details: [String: String] = [:]) {
        logQueue.async { [weak self] in
            guard let self = self else { return }
            
            let entry = AuditEntry(
                timestamp: Date(),
                event: event.rawValue,
                details: details,
                deviceId: UIDevice.current.identifierForVendor?.uuidString ?? "unknown",
                sessionId: self.sessionId
            )
            
            self.pendingLogs.append(entry)
            
            if self.pendingLogs.count >= self.maxPendingLogs {
                self.flushLogs()
            }
        }
    }
    
    func logTrade(order: TradeOrder) {
        log(event: .tradeSubmitted, details: [
            "orderId": order.id,
            "symbol": order.symbol,
            "side": order.side.rawValue,
            "type": order.type.rawValue,
            "quantity": "\(order.quantity)",
            "clientOrderId": order.clientOrderId
        ])
    }
    
    private func flushLogs() {
        let logsToSend = pendingLogs
        pendingLogs.removeAll()
        
        Task {
            do {
                struct LogBatch: Codable {
                    let entries: [AuditEntry]
                }
                let _: EmptyResponse = try await SecureAPIClient.shared.request(
                    endpoint: "/audit/logs",
                    method: "POST",
                    body: LogBatch(entries: logsToSend)
                )
            } catch {
                // Re-queue failed logs
                logQueue.async { [weak self] in
                    self?.pendingLogs.insert(contentsOf: logsToSend, at: 0)
                }
            }
        }
    }
    
    func newSession() {
        sessionId = UUID().uuidString
    }
}

struct EmptyResponse: Codable {}

// MARK: - Session Manager

final class SessionManager: ObservableObject {
    
    static let shared = SessionManager()
    
    @Published var isAuthenticated = false
    @Published var requiresBiometric = false
    @Published var sessionExpired = false
    
    private var sessionTimer: Timer?
    private let sessionTimeout: TimeInterval = 900 // 15 minutes
    private var lastActivityTime = Date()
    private let activityLock = NSLock()
    
    private init() {
        setupInactivityMonitoring()
    }
    
    func login(username: String, password: String) async throws {
        // Integrity check before login
        let integrity = DeviceIntegrityChecker.shared.performFullIntegrityCheck()
        if integrity.isJailbroken {
            AuditLogger.shared.log(event: .integrityCheckFailed, details: [
                "reasons": integrity.failureReasons.joined(separator: ", ")
            ])
            throw LoginError.deviceCompromised
        }
        
        struct LoginRequest: Codable {
            let username: String
            let password: String
            let deviceId: String
            let deviceFingerprint: String
        }
        
        struct LoginResponse: Codable {
            let token: String
            let refreshToken: String
            let expiresIn: Int
            let requiresMFA: Bool
        }
        
        let deviceId = UIDevice.current.identifierForVendor?.uuidString ?? UUID().uuidString
        
        let request = LoginRequest(
            username: username,
            password: password,
            deviceId: deviceId,
            deviceFingerprint: generateFingerprint()
        )
        
        let response: LoginResponse = try await SecureAPIClient.shared.request(
            endpoint: "/auth/login",
            method: "POST",
            body: request,
            requiresAuth: false
        )
        
        SecureAPIClient.shared.setAuthToken(response.token)
        
        // Store refresh token securely
        if let refreshData = response.refreshToken.data(using: .utf8),
           let encrypted = try? EncryptionManager.shared.encrypt(refreshData) {
            try? SecureKeychainManager.shared.store(key: "refresh_token", data: encrypted, requireBiometric: true)
        }
        
        await MainActor.run {
            self.isAuthenticated = true
            self.sessionExpired = false
        }
        
        resetActivityTimer()
        AuditLogger.shared.log(event: .login, details: ["method": "password"])
    }
    
    func authenticateWithBiometric() async throws {
        return try await withCheckedThrowingContinuation { continuation in
            BiometricAuthManager.shared.authenticateUser(reason: "Authenticate to access your trading account") { result in
                switch result {
                case .success:
                    AuditLogger.shared.log(event: .biometricAuth, details: ["result": "success"])
                    
                    // Retrieve and decrypt stored token
                    Task {
                        do {
                            let encryptedToken = try SecureKeychainManager.shared.retrieve(key: "auth_token")
                            let tokenData = try EncryptionManager.shared.decrypt(encryptedToken)
                            if let token = String(data: tokenData, encoding: .utf8) {
                                SecureAPIClient.shared.setAuthToken(token)
                                await MainActor.run {
                                    self.isAuthenticated = true
                                    self.sessionExpired = false
                                }
                                self.resetActivityTimer()
                                continuation.resume()
                            } else {
                                continuation.resume(throwing: LoginError.tokenRetrievalFailed)
                            }
                        } catch {
                            continuation.resume(throwing: LoginError.tokenRetrievalFailed)
                        }
                    }
                    
                case .failure(let error):
                    AuditLogger.shared.log(event: .biometricAuth, details: ["result": "failure", "error": "\(error)"])
                    continuation.resume(throwing: LoginError.biometricFailed)
                }
            }
        }
    }
    
    func logout() {
        SecureAPIClient.shared.clearAuthToken()
        sessionTimer?.invalidate()
        sessionTimer = nil
        
        Task { @MainActor in
            isAuthenticated = false
        }
        
        AuditLogger.shared.log(event: .logout)
        AuditLogger.shared.newSession()
    }
    
    func recordActivity() {
        activityLock.lock()
        lastActivityTime = Date()
        activityLock.unlock()
    }
    
    private func setupInactivityMonitoring() {
        sessionTimer = Timer.scheduledTimer(withTimeInterval: 60, repeats: true) { [weak self] _ in
            self?.checkInactivity()
        }
    }
    
    private func checkInactivity() {
        activityLock.lock()
        let elapsed = Date().timeIntervalSince(lastActivityTime)
        activityLock.unlock()
        
        if elapsed > sessionTimeout {
            DispatchQueue.main.async {
                self.sessionExpired = true
                self.isAuthenticated = false
            }
            SecureAPIClient.shared.clearAuthToken()
            AuditLogger.shared.log(event: .sessionExpired)
        }
    }
    
    private func resetActivityTimer() {
        activityLock.lock()
        lastActivityTime = Date()
        activityLock.unlock()
    }
    
    private func generateFingerprint() -> String {
        let info = "\(UIDevice.current.identifierForVendor?.uuidString ?? "")-\(UIDevice.current.model)-\(UIDevice.current.systemVersion)"
        if let data = info.data(using: .utf8) {
            return SHA256.hash(data: data).compactMap { String(format: "%02x", $0) }.joined()
        }
        return UUID().uuidString
    }
    
    enum LoginError: Error, LocalizedError {
        case deviceCompromised
        case biometricFailed
        case tokenRetrievalFailed
        case invalidCredentials
        case mfaRequired
        
        var errorDescription: String? {
            switch self {
            case .deviceCompromised: return "This device has been compromised. Trading is not allowed."
            case .biometricFailed: return "Biometric authentication failed."
            case .tokenRetrievalFailed: return "Failed to retrieve authentication token."
            case .invalidCredentials: return "Invalid username or password."
            case .mfaRequired: return "Multi-factor authentication required."
            }
        }
    }
}

// MARK: - Rate Limiter

final class RateLimiter {
    
    private var timestamps: [String: [Date]] = [:]
    private let lock = NSLock()
    
    struct Limit {
        let maxRequests: Int
        let windowSeconds: TimeInterval
    }
    
    private let limits: [String: Limit] = [
        "order_submit": Limit(maxRequests: 10, windowSeconds: 60),
        "order_cancel": Limit(maxRequests: 20, windowSeconds: 60),
        "quote_fetch": Limit(maxRequests: 60, windowSeconds: 60)
    ]
    
    func checkLimit(for action: String) -> Bool {
        lock.lock()
        defer { lock.unlock() }
        
        guard let limit = limits[action] else { return true }
        
        let now = Date()
        let windowStart = now.addingTimeInterval(-limit.windowSeconds)
        
        // Clean old timestamps
        timestamps[action] = (timestamps[action] ?? []).filter { $0 > windowStart }
        
        let count = timestamps[action]?.count ?? 0
        if count >= limit.maxRequests {
            return false
        }
        
        timestamps[action, default: []].append(now)
        return true
    }
}

// MARK: - Anti-Tampering Runtime Checks

final class RuntimeProtection {
    
    static let shared = RuntimeProtection()
    private var checkTimer: Timer?
    
    private init() {}
    
    func startContinuousMonitoring() {
        checkTimer = Timer.scheduledTimer(withTimeInterval: 30, repeats: true) { [weak self] _ in
            self?.performRuntimeChecks()
        }
    }
    
    func stopMonitoring() {
        checkTimer?.invalidate()
        checkTimer = nil
    }
    
    private func performRuntimeChecks() {
        // Check for debugger
        if DeviceIntegrityChecker.shared.performFullIntegrityCheck().isDebugged {
            AuditLogger.shared.log(event: .suspiciousActivity, details: ["type": "debugger_detected_runtime"])
            handleCompromise()
        }
        
        // Check for method swizzling on critical methods
        checkMethodIntegrity()
        
        // Verify no suspicious dylibs loaded at runtime
        checkDynamicLibraries()
    }
    
    private func checkMethodIntegrity() {
        // Verify critical class methods haven't been swizzled
        let criticalSelectors: [(AnyClass, Selector)] = [
            (SecureAPIClient.self, #selector(URLSessionDelegate.urlSession(_:didReceive:completionHandler:)))
        ]
        
        for (cls, sel) in criticalSelectors {
            if let method = class_getInstanceMethod(cls, sel) {
                let imp = method_getImplementation(method)
                // Store and compare implementation pointers
                // In production, compare against known-good values
                _ = imp
            }
        }
    }
    
    private func checkDynamicLibraries() {
        let suspiciousLibs = ["frida", "cycript", "substrate", "substitute", "libhooker"]
        let imageCount = _dyld_image_count()
        
        for i in 0..<imageCount {
            if let imageName = _dyld_get_image_name(i) {
                let name = String(cString: imageName).lowercased()
                for lib in suspiciousLibs {
                    if name.contains(lib) {
                        AuditLogger.shared.log(event: .suspiciousActivity, details: [
                            "type": "suspicious_dylib",
                            "library": name
                        ])
                        handleCompromise()
                        return
                    }
                }
            }
        }
    }
    
    private func handleCompromise() {
        // Clear sensitive data
        SecureAPIClient.shared.clearAuthToken()
        try? SecureKeychainManager.shared.delete(key: "refresh_token")
        
        DispatchQueue.main.async {
            SessionManager.shared.logout()
            
            // Show alert to user
            if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
               let rootVC = windowScene.windows.first?.rootViewController {
                let alert = UIAlertController(
                    title: "Security Alert",
                    message: "A security issue has been detected. For your protection, you have been logged out.",
                    preferredStyle: .alert
                )
                alert.addAction(UIAlertAction(title: "OK", style: .default))
                rootVC.present(alert, animated: true)
            }
        }
    }
}

